var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"먼 옛날, 내 선조는 이 숲에 아름다운 저택을 세웠다.","JPN":"遠い昔、私の先祖はこの森に美しい邸宅を建てた。","ENG":"A long time ago, my ancestors built a beautiful mansion within this forest.","TWN":"很久以前，我的先祖在這片森林裡建了一棟漂亮的宅邸。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_9"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어릴 적에는 그 이유를 몰랐지만, 지금은 알 수 있다.","JPN":"小さい頃はその理由がわからなかったが、今ならわかる。","ENG":"Back then, I could not figure out why... But now I know.","TWN":"小時候我不知道原因，現在我知道了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_10"},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"바다 너머에서 어머니를 살릴 비법을 찾으려던 그는, 맞닥뜨리고 만 것이다.","JPN":"海の向こうでお母様を甦らす秘法を探していた彼は、出くわしてしまったのだ。","ENG":"For he had come across it, on his journey to find the cure to his mother’s illness.","TWN":"在大海彼岸尋找救活母親的方法的他，最找到了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_11"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"자신의 평생을, 아니, 누대에 걸쳐 봉인해야 할 금지된 지식을.","JPN":"一生、いや、代を渡って封印していかなければならない、禁止された知識に。","ENG":"He had found Forbidden Knowledge that would consume his whole life and bloodline to seal.","TWN":"找到需要耗盡他的一生，不，準確地說是，要耗盡幾代人封印的禁忌知識。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_12"},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 돌아오시자마자 뭘 그렇게 뚫어져라 보고 계시는 거죠?","JPN":"レジーナ様、お戻りになったばかりなのに、何をそんなに見つめているのですか？","ENG":"Miss Regina, what are you staring at?","TWN":"蕾佳娜，一回來你就盯著看什麼呢？"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_2"},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저를 연구해 주시기만을 기다리고 있답니다. 어서요.","JPN":"研究してくださるのを待っているのです。早く。","ENG":"We're waiting for you to start studying us. Please, proceed.","TWN":"我在等著你研究，快點吧。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_3"},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"참으세요. 이번 사건으로 학회는 양지로 지나치게 많이 노출됐습니다.","JPN":"我慢しなさい。この度の事件で、学会は日の当たるところにその姿を露出しすぎました。","ENG":"Save your urges. The Society has been exposed to the public eye for too long during this incident.","TWN":"先忍一忍，這次事件會讓學會過度地暴露於陽光下。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"햇빛을 본 부분들은 모조리 도려내야 해요.","JPN":"日に当たった部分はすべて切り取らなければなりません。","ENG":"We must cut out all of the parts that have been exposed to light.","TWN":"見光的部分都要挖掉。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"제물로 삼을 계획이시군요.","JPN":"生贄にするおつもりですね。","ENG":"You plan to make them sacrifice.","TWN":"你是打算把他們當成祭物嗎。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_4"},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 우선 건축학부와 철학부겠죠. 합중국에서 가장 날뛴 학부들이랍니다.","JPN":"そういうことでしたら、まずは建築学部と哲学部でしょう。合衆国でもっとも暴れていた学部です。","ENG":"Then it should be the Architecture and Philosophy Departments. They were most active in the States.","TWN":"那麼首先應該是建築學院和哲學院吧。他們是在合眾國最猖狂的學院。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_5"},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……그리고 고고학부까지.","JPN":"……そして考古学部も。","ENG":"...Followed by the Archeology Department.","TWN":"……還有考古學院。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"법학부장에게 서신을 보내야겠군요. 직접 처분하는 태도를 보여야 대화할 수 있을 겁니다.","JPN":"法学部長に手紙を送るべきですわね。直接処分する態度を見せないと、会話などできないはずです。","ENG":"I must go and write a letter to the Dean of Law. The only way to summon her will be to demonstrate that I will personally dispose of them.","TWN":"我得給法學院院長寫一封信。只有表現出親自處理的態度，才能和她對話。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"합중국 정부와 가교 역할을 할 인사가 필요해요.","JPN":"合衆国政府との間に立ってくれる人が必要です。","ENG":"I also need someone who can act as a diplomat with the States.","TWN":"我們需要在學會和合眾國政府之間發揮橋樑作用的人。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"사용한 뒤에는……","JPN":"使用した後は……","ENG":"After that...","TWN":"使用之後……"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"나는 두렵다.","JPN":"私は怖い。","ENG":"I am terrified.","TWN":"我很害怕。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_13"},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"언젠가, 이대로 모든 것이 익숙해지는 날이.","JPN":"いつか、このまますべてに慣れてしまう日が来ることが。","ENG":"That the day will come when I will get used to all of this.","TWN":"害怕總有一天，會對所有的事情變得熟悉又麻木的那一天。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_14"},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"파편들은 어떻게 되었죠?","JPN":"破片はどうなりましたか？","ENG":"What happened with the Fragments?","TWN":"碎片怎麼樣了？"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"합중국에 보낸 아이는 프리드웬이 망가뜨렸어요. 결국 일부만 회수할 수 있었답니다.","JPN":"合衆国に送った子は、プリドウェンに壊されてしまいました。結局、一部だけしか回収できませんでしたね。","ENG":"The one sent to the States was ruined by Prydwen. We were only able to retrieve parts of it.","TWN":"派去合眾國的孩子被普利多溫給毀了。最後只能回收一部分。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_6"},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이면세계로 보낸 아이는…… 글쎄요. 세라펠은 과연 무사할지.","JPN":"裏世界に送った子は……どうでしょう。セラフェルは果たして無事でしょうか。","ENG":"The one sent to Counterside... We don't know what happened to our baby or if Serapel is even safe...","TWN":"派去異界的孩子……不好說，塞拉費爾究竟是否平安無事。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_7"},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"학부들에게 파편을 회수한다고 전해야겠군요. 이견을 드러내면 도려낼 기회로 삼죠.","JPN":"学部に破片を回収すると伝えなければなりませんね。異論を唱えるようなら、切り取る口実にしましょう。","ENG":"Tell the departments that we are retrieving the Fragment. If they disagree, I shall take it as an opportunity to cut them out.","TWN":"我得告訴學院回收碎片。一旦出現分歧，就當成是剷除的機會吧。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"감정도, 추억도 접어 두고.","JPN":"感情も、思い出も置き去りにして。","ENG":"I leave behind all emotions and memories.","TWN":"收起感情，收起回憶。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_15"},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"모든 것은 오로지 냉철한 이성으로.","JPN":"すべてはただ冷徹な理性で。","ENG":"Everything shall be dealt with reason only.","TWN":"一切只用冷靜的理智思考。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_16"},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"다른 학부들이 관리해 온 주민들도 모두 불러들여야겠군요.","JPN":"他の学部が管理してきた住民も、みな呼び寄せる必要がありますね。","ENG":"Call in the residents managed by other departments as well.","TWN":"得把其他學院管理的居民也全都叫過來。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"제대로 교육을 시켜 제 발로 영지를 벗어날 수 있게 하려면, 당분간 바쁘겠어요.","JPN":"ちゃんと教育して自分の足で領地を出られるようにしようとすると、しばらく忙しくなりますわ。","ENG":"It will take a lot of work to enlighten them and make them leave the estate on their own terms. It must be busy for a while.","TWN":"要想通過好好教育，讓他們可以自己走出領地，短期內應該都會很忙。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"먼 옛날, 내 선조는 이 숲에 아름다운 저택을 세웠다.","JPN":"遠い昔、私の先祖はこの森に美しい邸宅を建てた。","ENG":"A long time ago, my ancestors built a beautiful mansion within this forest.","TWN":"很久以前，我的先祖在這片森林裡建了一棟漂亮的宅邸。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_17"},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"어릴 적에는 그 이유를 몰랐지만, 지금은 알 수 있다.","JPN":"小さい頃はその理由がわからなかったが、今ならわかる。","ENG":"Back then, I could not figure out why... But now I know.","TWN":"小時候我不知道原因，現在我知道了。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_18"},{"id":"L29_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"리벳이 쑥대밭으로 만들어 놓은 거죠?","JPN":"リベットが荒らしたのですね？","ENG":"Rivet is the one behind this, no?","TWN":"是里維把它變成荒地的吧？"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_8"},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후후, 주민들이 개간하면 내년에는 레지나 님께서 좋아하실 만한 과실을 잔뜩 얻겠네요.","JPN":"ふふ、住民たちに開墾してもらえば、来年にはレジーナ様がお好きな果実をたくさん収穫できますね。","ENG":"Haha, by the time the residents cultivate next year, there will be plenty of fruit for you to enjoy, Miss Regina.","TWN":"呵呵，居民們開墾之後，明年應該就能結出許多蕾佳娜喜歡的果實了。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_9"},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……에델.","JPN":"……エデル。","ENG":"...Edel.","TWN":"……艾瑟兒。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 뭐든 말씀하세요, 학회장님.","JPN":"はい。何なりとお申しつけください、学会長。","ENG":"Yes. Tell me anything, President.","TWN":"嗯，你請說，學會長。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_10"},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"사탕을 사 와야겠어요.","JPN":"キャンディーを買ってきましょう。","ENG":"I need to get some candy.","TWN":"還要買些糖果回來。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"사탕이요?","JPN":"キャンディーですか？","ENG":"Candy?","TWN":"糖果？"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_11"},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"네. 기왕이면…… 계피맛이 좋겠네요.","JPN":"はい。せっかくなら……シナモン味がいいですね。","ENG":"Yes. I would prefer it if it is... cinnamon flavored.","TWN":"是的，既然如此……肉桂口味的應該不錯。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"봉인이라는 것은 웅장한 마법진도, 수수께끼 같은 주문도 필요없음을.","JPN":"封印というのは盛大な魔法陣も、謎のような呪文もいらない。","ENG":"There need not any grand magic circles nor complicated spells to seal.","TWN":"封印既不需要宏偉的魔法陣，也不需要謎語一般的咒語。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_19"},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"한마디의 말로도 주박은 성립한다는 사실을.","JPN":"一言の言葉でも呪縛は成立する。","ENG":"One word is enough.","TWN":"只需要一句話，咒術就能成立。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_20"},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이제 겨우, 집으로 돌아온 기분이에요. 에델.","JPN":"ようやく、家に帰ってきた気分ですわ。エデル。","ENG":"It feels like I finally made it home, Edel.","TWN":"現在，我終於有種回家的心情了，艾瑟兒。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"……네. 어서오세요, 레지나 님.","JPN":"……はい。お帰りなさい、レジーナ様。","ENG":"...Welcome back, Miss. Regina.","TWN":"……是的，歡迎你回家，蕾佳娜。"},"stage":{"bg":"ESPR2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_12"}]`);export{e as default};